import React, { useContext } from 'react';
import { CartContext } from '../context/CartContext';
import { useNavigate } from 'react-router-dom';
import API from '../services/api';

const Checkout = () => {
  const { cartItems, clearCart } = useContext(CartContext);
  const navigate = useNavigate();

  const total = cartItems.reduce((sum, item) => {
    const price = item.product.price * (1 - (item.product.discount || 0) / 100);
    return sum + price * item.qty;
  }, 0);

  const placeOrder = async () => {
    try {
      const orderItems = cartItems.map(i => ({ product: i.product._id, qty: i.qty }));
      await API.post('/orders', { orderItems, total });
      clearCart();
      alert('Order placed successfully!');
      navigate('/');
    } catch (err) {
      console.error(err);
      alert('Failed to place order');
    }
  };

  if (cartItems.length === 0) {
    return (
      <div className="container my-4">
        <h2>Your cart is empty.</h2>
      </div>
    );
  }

  return (
    <div className="container my-4">
      <h2>Checkout</h2>
      <ul className="list-group mb-3">
        {cartItems.map(item => (
          <li key={item.product._id} className="list-group-item d-flex justify-content-between align-items-center">
            {item.product.name} x {item.qty}
            <span>${(item.product.price * item.qty).toFixed(2)}</span>
          </li>
        ))}
      </ul>
      <h4>Total: ${total.toFixed(2)}</h4>
      <button className="btn btn-success" onClick={placeOrder}>Place Order</button>
    </div>
  );
};

export default Checkout;
